export const NAPI_BUILD_HTML = "<h1 id=\"napi-build\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build\" aria-hidden=\"true\">#</a> napi-build</h1>\n<h2 id=\"napi-build-v2.3.2\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build-v2.3.2\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build-v2.3.2\" target=\"_blank\" rel=\"noopener\">napi-build-v2.3.2</a></h2>\n<p>5/13/2026</p>\n<h3 id=\"fixed\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#fixed\" aria-hidden=\"true\">#</a> Fixed</h3>\n<ul>\n<li><em>(build)</em> on openbsd, work around local thread storage destructor crash after DSO unloading using '-z, nodelete' linker flag (<a href=\"https://github.com/napi-rs/napi-rs/pull/3274\">#3274</a>)</li>\n</ul>\n<h2 id=\"napi-build-v2.3.1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build-v2.3.1\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build-v2.3.1\" target=\"_blank\" rel=\"noopener\">napi-build-v2.3.1</a></h2>\n<p>11/10/2025</p>\n<h3 id=\"fixed-1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#fixed-1\" aria-hidden=\"true\">#</a> Fixed</h3>\n<ul>\n<li><em>(build)</em> add back undefined symbols lookup behavior (<a href=\"https://github.com/napi-rs/napi-rs/pull/3015\">#3015</a>)</li>\n</ul>\n<h2 id=\"napi-build-v2.3.0\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build-v2.3.0\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build-v2.3.0\" target=\"_blank\" rel=\"noopener\">napi-build-v2.3.0</a></h2>\n<p>11/6/2025</p>\n<h3 id=\"added\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#added\" aria-hidden=\"true\">#</a> Added</h3>\n<ul>\n<li><em>(sys)</em> use libloading to load napi symbols at runtime on all platform (<a href=\"https://github.com/napi-rs/napi-rs/pull/2996\">#2996</a>)</li>\n</ul>\n<h2 id=\"napi-build-v2.2.4\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build-v2.2.4\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build-v2.2.4\" target=\"_blank\" rel=\"noopener\">napi-build-v2.2.4</a></h2>\n<p>10/24/2025</p>\n<h3 id=\"fixed-2\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#fixed-2\" aria-hidden=\"true\">#</a> Fixed</h3>\n<ul>\n<li><em>(build)</em> export <code>emnapi_thread_crashed</code> (<a href=\"https://github.com/napi-rs/napi-rs/pull/2920\">#2920</a>)</li>\n</ul>\n<h3 id=\"other\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#other\" aria-hidden=\"true\">#</a> Other</h3>\n<ul>\n<li><em>(napi)</em> bump rust-version (<a href=\"https://github.com/napi-rs/napi-rs/pull/2966\">#2966</a>)</li>\n</ul>\n<h2 id=\"napi-build-v2.2.3\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build-v2.2.3\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build-v2.2.3\" target=\"_blank\" rel=\"noopener\">napi-build-v2.2.3</a></h2>\n<p>7/24/2025</p>\n<h3 id=\"other-1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#other-1\" aria-hidden=\"true\">#</a> Other</h3>\n<ul>\n<li><em>(cli)</em> setjmp link path (<a href=\"https://github.com/napi-rs/napi-rs/pull/2808\">#2808</a>)</li>\n</ul>\n<h2 id=\"napi-build%402.2.2\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%402.2.2\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%402.2.2\" target=\"_blank\" rel=\"noopener\">napi-build@2.2.2</a></h2>\n<p>6/30/2025</p>\n<h2 id=\"what's-changed\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#what's-changed\" aria-hidden=\"true\">#</a> What's Changed</h2>\n<ul>\n<li>fix(build): increase wasi stack size by <a href=\"https://github.com/CPunisher\">@CPunisher</a> in <a href=\"https://github.com/napi-rs/napi-rs/pull/2748\">https://github.com/napi-rs/napi-rs/pull/2748</a></li>\n</ul>\n<p><strong>Full Changelog</strong>: <a href=\"https://github.com/napi-rs/napi-rs/compare/napi@3.0.0-beta.10...napi-build@2.2.2\">https://github.com/napi-rs/napi-rs/compare/napi@3.0.0-beta.10...napi-build@2.2.2</a></p>\n<h2 id=\"napi-build%402.2.1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%402.2.1\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%402.2.1\" target=\"_blank\" rel=\"noopener\">napi-build@2.2.1</a></h2>\n<p>6/4/2025</p>\n<h2 id=\"what's-changed-1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#what's-changed-1\" aria-hidden=\"true\">#</a> What's Changed</h2>\n<p>No significant change, add environment change detection for napi-derive beta versions</p>\n<p><strong>Full Changelog</strong>: <a href=\"https://github.com/napi-rs/napi-rs/compare/napi@3.0.0-beta.5...napi-build@2.2.1\">https://github.com/napi-rs/napi-rs/compare/napi@3.0.0-beta.5...napi-build@2.2.1</a></p>\n<h2 id=\"napi-build%402.2.0\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%402.2.0\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%402.2.0\" target=\"_blank\" rel=\"noopener\">napi-build@2.2.0</a></h2>\n<p>5/16/2025</p>\n<h2 id=\"what's-changed-2\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#what's-changed-2\" aria-hidden=\"true\">#</a> What's Changed</h2>\n<ul>\n<li>feat: auto invalid type gen by <a href=\"https://github.com/Brooooooklyn\">@Brooooooklyn</a> in <a href=\"https://github.com/napi-rs/napi-rs/pull/2638\">https://github.com/napi-rs/napi-rs/pull/2638</a></li>\n</ul>\n<p><strong>Full Changelog</strong>: <a href=\"https://github.com/napi-rs/napi-rs/compare/napi-build@2.1.6...napi-build@2.2.0\">https://github.com/napi-rs/napi-rs/compare/napi-build@2.1.6...napi-build@2.2.0</a></p>\n<h2 id=\"napi-build%402.1.6\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%402.1.6\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%402.1.6\" target=\"_blank\" rel=\"noopener\">napi-build@2.1.6</a></h2>\n<p>3/22/2025</p>\n<h2 id=\"what's-changed-3\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#what's-changed-3\" aria-hidden=\"true\">#</a> What's Changed</h2>\n<ul>\n<li>perf(build): remove <code>--export-dynamic</code> flag in wasi compilation by <a href=\"https://github.com/CPunisher\">@CPunisher</a> in <a href=\"https://github.com/napi-rs/napi-rs/pull/2523\">https://github.com/napi-rs/napi-rs/pull/2523</a></li>\n</ul>\n<p><strong>Full Changelog</strong>: <a href=\"https://github.com/napi-rs/napi-rs/compare/napi@3.0.0-alpha.33...napi-build@2.1.6\">https://github.com/napi-rs/napi-rs/compare/napi@3.0.0-alpha.33...napi-build@2.1.6</a></p>\n<h2 id=\"napi-build%402.1.5\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%402.1.5\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%402.1.5\" target=\"_blank\" rel=\"noopener\">napi-build@2.1.5</a></h2>\n<p>2/25/2025</p>\n<h2 id=\"what's-changed-4\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#what's-changed-4\" aria-hidden=\"true\">#</a> What's Changed</h2>\n<ul>\n<li>refactor: link crt1-reactor.o as poor man's wasi-exec-model=reactor by <a href=\"https://github.com/Brooooooklyn\">@Brooooooklyn</a> in <a href=\"https://github.com/napi-rs/napi-rs/pull/2480\">https://github.com/napi-rs/napi-rs/pull/2480</a></li>\n</ul>\n<p><strong>Full Changelog</strong>: <a href=\"https://github.com/napi-rs/napi-rs/compare/napi@3.0.0-alpha.30...napi-build@2.1.5\">https://github.com/napi-rs/napi-rs/compare/napi@3.0.0-alpha.30...napi-build@2.1.5</a></p>\n<h2 id=\"napi-build%402.1.1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%402.1.1\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%402.1.1\" target=\"_blank\" rel=\"noopener\">napi-build@2.1.1</a></h2>\n<p>2/18/2024</p>\n<h2 id=\"what's-changed-5\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#what's-changed-5\" aria-hidden=\"true\">#</a> What's Changed</h2>\n<ul>\n<li>feat(cli,build): support setjmp.h by <a href=\"https://github.com/Brooooooklyn\">@Brooooooklyn</a> in <a href=\"https://github.com/napi-rs/napi-rs/pull/1958\">https://github.com/napi-rs/napi-rs/pull/1958</a></li>\n</ul>\n<p><strong>Full Changelog</strong>: <a href=\"https://github.com/napi-rs/napi-rs/compare/napi@2.15.2...napi-build@2.1.1\">https://github.com/napi-rs/napi-rs/compare/napi@2.15.2...napi-build@2.1.1</a></p>\n<h2 id=\"napi-build%402.0.1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%402.0.1\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%402.0.1\" target=\"_blank\" rel=\"noopener\">napi-build@2.0.1</a></h2>\n<p>6/10/2022</p>\n<h2 id=\"what's-changed-6\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#what's-changed-6\" aria-hidden=\"true\">#</a> What's Changed</h2>\n<ul>\n<li>fix: android builds broken by actions default ndk version bump by <a href=\"https://github.com/forehalo\">@forehalo</a> in <a href=\"https://github.com/napi-rs/napi-rs/pull/1207\">https://github.com/napi-rs/napi-rs/pull/1207</a></li>\n</ul>\n<p><strong>Full Changelog</strong>: <a href=\"https://github.com/napi-rs/napi-rs/compare/napi-build@2.0.0...napi-build@2.0.1\">https://github.com/napi-rs/napi-rs/compare/napi-build@2.0.0...napi-build@2.0.1</a></p>\n<h2 id=\"napi-build%402.0.0\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%402.0.0\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%402.0.0\" target=\"_blank\" rel=\"noopener\">napi-build@2.0.0</a></h2>\n<p>5/7/2022</p>\n<h2 id=\"what's-changed-7\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#what's-changed-7\" aria-hidden=\"true\">#</a> What's Changed</h2>\n<h3 id=\"breaking\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#breaking\" aria-hidden=\"true\">#</a> <strong>BREAKING</strong></h3>\n<ul>\n<li>Use <code>libloading</code> on Windows, remove <code>node-{arch}.lib</code> files in <code>napi-build</code> by <a href=\"https://github.com/Brooooooklyn\">@Brooooooklyn</a> in <a href=\"https://github.com/napi-rs/napi-rs/pull/1167\">https://github.com/napi-rs/napi-rs/pull/1167</a></li>\n</ul>\n<p><strong>You must use <code>napi 2.4+</code> with the <code>napi-build@2</code></strong></p>\n<p><strong>Full Changelog</strong>: <a href=\"https://github.com/napi-rs/napi-rs/compare/napi-derive@2.3.3...napi-build@2.0.0\">https://github.com/napi-rs/napi-rs/compare/napi-derive@2.3.3...napi-build@2.0.0</a></p>\n<h2 id=\"napi-build%401.2.1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%401.2.1\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%401.2.1\" target=\"_blank\" rel=\"noopener\">napi-build@1.2.1</a></h2>\n<p>12/22/2021</p>\n<h2 id=\"what's-changed-8\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#what's-changed-8\" aria-hidden=\"true\">#</a> What's Changed</h2>\n<ul>\n<li>fix: keep <code>.d.ts</code> and <code>.js</code> untouched if native doesn't change by <a href=\"https://github.com/forehalo\">@forehalo</a> in <a href=\"https://github.com/napi-rs/napi-rs/pull/941\">https://github.com/napi-rs/napi-rs/pull/941</a></li>\n</ul>\n<p><strong>Full Changelog</strong>: <a href=\"https://github.com/napi-rs/napi-rs/compare/napi@2.0.0...napi-build@1.2.1\">https://github.com/napi-rs/napi-rs/compare/napi@2.0.0...napi-build@1.2.1</a></p>\n<h2 id=\"napi-build%401.2.0\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%401.2.0\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%401.2.0\" target=\"_blank\" rel=\"noopener\">napi-build@1.2.0</a></h2>\n<p>12/2/2021</p>\n<h3 id=\"features\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#features\" aria-hidden=\"true\">#</a> Features</h3>\n<ul>\n<li>Update Windows x64 and Windows x86 lib file to <code>Node.js@17.2.0</code></li>\n</ul>\n<p>⚠️ There is no official Node.js build for <strong>Windows ARM64</strong> for now: <a href=\"https://github.com/nodejs/build/issues/2450\">https://github.com/nodejs/build/issues/2450</a></p>\n<p>So if you want build library for <strong>Windows ARM64</strong>, you can not use <code>experimental</code> features for now.</p>\n<h2 id=\"napi-build%401.1.2\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%401.1.2\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%401.1.2\" target=\"_blank\" rel=\"noopener\">napi-build@1.1.2</a></h2>\n<p>11/25/2021</p>\n<h3 id=\"bugfix\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#bugfix\" aria-hidden=\"true\">#</a> Bugfix</h3>\n<ul>\n<li>Fix cargo:rerun-if commands #871 <a href=\"https://github.com/sam3d\">@sam3d</a></li>\n</ul>\n<h2 id=\"napi-build%401.1.0\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%401.1.0\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%401.1.0\" target=\"_blank\" rel=\"noopener\">napi-build@1.1.0</a></h2>\n<p>6/7/2021</p>\n<h3 id=\"feature\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#feature\" aria-hidden=\"true\">#</a> Feature</h3>\n<ul>\n<li>feat(build): remove <code>ureq</code> to support windows arm64  #587</li>\n</ul>\n<h2 id=\"napi-build%401.1.0-beta.0\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%401.1.0-beta.0\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%401.1.0-beta.0\" target=\"_blank\" rel=\"noopener\">napi-build@1.1.0-beta.0</a></h2>\n<p>6/2/2021</p>\n<h3 id=\"feature-1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#feature-1\" aria-hidden=\"true\">#</a> Feature</h3>\n<ul>\n<li>feat(build): remove <code>ureq</code> to support windows arm64</li>\n</ul>\n<h2 id=\"napi-build%401.0.1\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#napi-build%401.0.1\" aria-hidden=\"true\">#</a> <a href=\"https://github.com/napi-rs/napi-rs/releases/tag/napi-build%401.0.1\" target=\"_blank\" rel=\"noopener\">napi-build@1.0.1</a></h2>\n<p>1/4/2021</p>\n<h1 id=\"chore\" tabindex=\"-1\"><a class=\"header-anchor\" href=\"#chore\" aria-hidden=\"true\">#</a> Chore</h1>\n<ul>\n<li>Upgrade <a href=\"https://github.com/algesten/ureq\">ureq</a> to 2.0</li>\n</ul>\n"

